<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Bouncing-Ball Physics Playground</title>
    <style>
        body {
            margin: 0;
            padding: 0;
            background-color: #333;
            color: white;
            font-family: sans-serif;
        }

        canvas {
            border: 2px solid #444;
            background-color: transparent;
        }

        .container {
            display: flex;
            justify-content: center;
            align-items: center;
            height: 400px;
            margin-bottom: 20px;
        }

        button {
            padding: 10px 15px;
            font-size: 16px;
            cursor: pointer;
        }

        #drop {
            background-color: #ff0000;
            color: white;
            border: none;
            margin-top: 10px;
        }

        #play, #clear {
            background-color: #333;
            color: white;
            border: none;
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>Bouncing-Ball Physics Playground</h1>

        <button id="drop">Drop a new ball</button>
        <button id="play" onclick="toggleAnimation()">Play Animation</button>
        <button id="clear" onclick="clearAllBalls()">Clear all balls</button>

        <canvas id="sim"></canvas>
    </div>

    <script>
        // Grading API implementation
        window.sim = {
            w: 400,
            h: 400,
            balls: [],
            addBall(x, y, vx=0, vy=0, r?), 
            clear(), 
            step(dt=1)
        };

        // Helper functions for physics simulation
        function updateVelocity(ball) {
            ball.vx *= dt;
            ball.vy += g * dt;  // gravity acceleration
        }

        function checkCollisions(positions, velocity, radius, width, height) {
            const balls = positions.map(b => ({
                x: b.x,
                y: b.y,
                vx: b.vx,
                vy: b.vy,
                r: radius
            }));

            for (const ball of balls) {
                // Check left wall collision
                if (ball.x + ball.vx * dt < 0 || 
                    ball.x + ball.vx * dt > width - 1) {
                    ball.x = 0;
                    ball.vx *= -1;  // reverse horizontal velocity
                }

                // Check right wall collision
                if (ball.x + ball.vx * dt < width - 1 || 
                    ball.x + ball.vx * dt > width) {
                    ball.x = width - 1;
                    ball.vx *= -1;  // reverse horizontal velocity
                }

                // Check top wall collision
                if (ball.y + ball.vy * dt < 0 || 
                    ball.y + ball.vy * dt > height - 1) {
                    ball.y = 0;
                    ball.vy *= -1;  // reverse vertical velocity
                }

                // Check bottom wall collision
                if (ball.y + ball.vy * dt < height - 1 || 
                    ball.y + ball.vy * dt > height) {
                    ball.y = height - 1;
                    ball.vy *= -1;  // reverse vertical velocity
                }
            }
        }

        function drawBall(ball, canvas) {
            const x = ball.x;
            const y = ball.y;
            const radius = ball.r;

            // Draw circle with rounded corners
            const cx = Math.floor(x + radius * Math.sqrt(2));
            const cy = Math.floor(y + radius * Math.sqrt(2));
            const width = 2 * radius;
            const height = 2 * radius;

            canvas.getContext('2d').fillStyle('#444');
            canvas.beginPath();
            canvas.arc(cx, cy, width, 0, Math.PI * 2);
            canvas.fill();
        }

        // Initialize simulation with a single ball at center
        function initSimulation() {
            const canvas = document.getElementById('sim');
            const ctx = canvas.getContext('2d');

            // Set initial parameters
            const radius = 10;
            const width = 400;
            const height = 400;
            const g = 0.001;  // small gravity acceleration

            // Create a single ball at center with default velocity (0,0)
            window.sim.balls.push({
                x: Math.floor(width / 2),
                y: Math.floor(height / 2),
                vx: 0,
                vy: 0,
                r: radius
            });

            // Draw initial ball
            drawBall(window.sim.balls[0], canvas);
        }

        // Add a new ball to the simulation
        function addBall(x, y, vx=0, vy=0, r?) {
            window.sim.balls.push({
                x: x,
                y: y,
                vx: vx,
                vy: vy,
                r: r ? r : radius
            });

            // Update positions and velocities for next step
            updateVelocity(window.sim.balls[window.sim.balls.length - 1]);
        }

        // Remove all balls from simulation
        function clearAllBalls() {
            window.sim.balls = [];
        }

        // Advance simulation one step (update positions, velocities, and draw)
        function step(dt=1) {
            checkCollisions(window.sim.balls, 
                { x: ball.x, y: ball.y, vx: ball.vx, vy: ball.vy }, 
                window.sim.w, window.sim.h);

            // Update positions based on velocity for next step
            for (let i = 0; i < window.sim.balls.length; i++) {
                const ball = window.sim.balls[i];
                ball.x += ball.vx * dt;
                ball.y += ball.vy * dt;

                // Draw the ball at new position
                drawBall(ball, canvas);
            }
        }

        // Toggle animation state (play or clear)
        function toggleAnimation() {
            if (window.sim.balls.length > 0) {
                window.sim.clear();
                initSimulation();
            } else {
                window.sim.addBall(200, 200, 10, 1, 5);
            }
        }

        // Handle canvas click to add a ball
        function handleCanvasClick(event) {
            const x = event.clientX;
            const y = event.clientY;

            if (window.sim.balls.length === 0) {
                window.sim.addBall(x, y, 10, 1, 5);
            }
        }
    </script>
</body>
</html>
